import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists(): return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing: existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]: existing[ch][v] = html

PSALMS = {
"22": {
"2": "<p><strong>ʾĕlōhay ʾezʿaq yômām wĕlōʾ taʿăneh</strong> (<em>ʾĕlōhay ʾezʿaq yômām wĕlōʾ taʿăneh</em>): 'O my God, I cry by day, but you do not answer.' The sustained cry yômām ... wĕlāylâ ('by day ... and by night') conveys relentlessness — prayer without intermission yet without response. The phrase wĕlōʾ dûmîyâ lî, 'and I have no silence/rest,' is better read 'there is no silence for me' — the psalmist cannot stop crying out because the distress is too great. The silence of God is the opposite of the heard cry in Ps 9:12; it is the extremity that makes this psalm the most anguished in the Psalter.</p>",
"3": "<p><strong>wĕʾattâ qādôš yôšēb tĕhillôt yiśrāʾēl</strong> (<em>wĕʾattâ qāḏôš yôšēḇ tĕhillôṯ yiśrāʾēl</em>): 'Yet you are holy, enthroned on the praises of Israel.' The waw-adversative wĕʾattâ ('but you') introduces the theological anchor: God's holiness and his enthronement on praise are not negated by the psalmist's experience of abandonment. The noun tĕhillôt ('praises') used as the seat of divine enthronement means that Israel's worship constitutes the medium in which God is present and sovereign — a remarkable theology of liturgy. The verb yōšēb ('sit/dwell') connects to the divine throne imagery of Ps 9:7 and 11:4.</p>",
"4": "<p><strong>bĕkā bāṭĕḥû ʾăbōtênû bāṭĕḥû wattĕpallĕṭēm</strong> (<em>bĕḵā ḇāṭĕḥû ʾăḇōṯênû bāṭĕḥû wattĕp̄allĕṭēm</em>): 'In you our fathers trusted; they trusted, and you delivered them.' The double bāṭĕḥû ('they trusted ... they trusted') is emphatic — the ancestral trust was complete and unequivocal. The result: wattĕpallĕṭēm ('and you delivered them') — a perfect of completed action. The pattern establishes precedent: trust in YHWH has historically issued in rescue. The psalmist invokes this history as the basis for his own prayer — not to claim guaranteed deliverance but to remind God of his own track record.</p>",
"5": "<p><strong>ʾēlêkā zāʿăqû wĕnimmalāṭû</strong> (<em>ʾēlêḵā zāʿăqû wĕnimmalāṭû</em>): 'To you they cried and were saved.' The verb zāʿaq ('cry aloud, cry for help') is repeated from v.2 in a contrasting pattern: the fathers cried (v.5) and were saved; the psalmist cries (v.2) and is not answered. The phrase bĕkā bāṭĕḥû wĕlōʾ bôšû, 'in you they trusted and were not put to shame,' uses bôš ('be ashamed, disappointed') — the ultimate fear of the one whose prayer goes unanswered. The fathers' non-shame is the psalmist's hope and the ground of his continued crying.</p>",
"6": "<p><strong>wĕʾānōkî tôlaʿat wĕlōʾ-ʾîš</strong> (<em>wĕʾānōḵî ṯôlaʿaṯ wĕlōʾ-ʾîš</em>): 'But I am a worm and not a man.' The contrast wĕʾānōkî ('but I') is emphatic: the honored ancestors (vv.4-5) versus the degraded present. The noun tôlaʿat ('worm') is used for a crimson-producing grub (tôlāʿ); to be a worm is to be beneath the dignity of human personhood. The phrase ḥerpat ʾādām ûbĕzûy ʿām, 'a reproach of mankind and despised by the people,' uses ḥerpâ ('reproach, taunt') and bāzâ ('despised') — social contempt that reduces a person to sub-human status. The NT applies this to Christ's passion (cf. Isa 53:3).</p>",
"7": "<p><strong>kol-rōʾay yilʿăgû-lî</strong> (<em>ḵol-rōʾay yilʿăḡû-lî</em>): 'All who see me mock me.' The verb lāʿag ('to mock, deride') describes the social humiliation of the lamenter. The specific gestures — yaptîrû bĕśāpâ yānîʿû rōʾš, 'they make mouths at me, they wag their heads' — are the recognized gestures of contempt and derision in the ancient world (cf. Job 16:4; Lam 2:15). Matthew explicitly cites this verse in the passion narrative: 'those who passed by derided him, wagging their heads' (Matt 27:39), understanding the mockers at the cross as fulfilling the posture described here.</p>",
"8": "<p><strong>gōl ʾel-YHWH yĕpallĕṭēhû</strong> (<em>ḡōl ʾel-YHWH yĕp̄allĕṭēhû</em>): 'He rolled his burden upon the LORD; let him deliver him.' The qal imperative gōl ('roll!') draws on the idiom of rolling a burden onto another (cf. Prov 16:3). The mockers' quotation — yitpallĕṭēhû kî ḥāpeṣ bô, 'let him rescue him, for he delights in him' — is savage irony: if YHWH truly favors this person, let him prove it by rescue. Matthew 27:43 cites this verse directly: 'He trusts in God; let God deliver him now, if he desires him; for he said, I am the Son of God.' The verbal correspondence between the Psalm's mockers and the crucifixion mockers is exact.</p>",
"9": "<p><strong>kî-ʾattâ gōḥî mibbāṭen</strong> (<em>kî-ʾattâ ḡōḥî mibbāṭen</em>): 'Yet you are he who took me from the womb.' The particle kî ('yet, for') introduces a counter-argument to the mockery: the psalmist appeals to the intimacy of his origins. The verb gōḥî (hiphil of gāḥ, 'to burst forth, draw out') describes the violent creative act of birth — YHWH was the one who drew him out. The phrase maḇṭîḥî ʿal šĕdê ʾimmî, 'you made me trust at my mother's breasts,' means that even the infant's trust in the mother's provision was mediated by YHWH — divine care precedes rational faith.</p>",
"10": "<p><strong>ʿālêkā hošlaktî mērāḥem</strong> (<em>ʿālêḵā hošlaktî mērāḥem</em>): 'Upon you was I cast from birth.' The hophal hošlaktî ('I was cast/thrown') — a striking passive that places the infant's placement in God's hands — inverts the language of abandonment: the psalmist was not abandoned but cast upon YHWH from the womb (mērāḥem, 'from the womb'). The phrase mibbeten ʾimmî ʾēlî ʾāttâ, 'from my mother's womb you have been my God,' makes the covenant relationship pre-rational and pre-voluntary — YHWH is 'my God' from before the psalmist could choose it. This grounds the prayer: if you have been my God since birth, you cannot abandon me now.</p>",
"11": "<p><strong>ʾal-tirhaq mimmennî kî ṣārâ qĕrôbâ</strong> (<em>ʾal-tirhaq mimmennî kî ṣārâ qĕrôbâ</em>): 'Be not far from me, for trouble is near.' The negative imperative ʾal-tirhaq ('do not be far') is the direct petition — the counterpart to the lament of v.1 (God is far). The crisis: ṣārâ qĕrôbâ ('trouble is near') contrasts with YHWH who seems far — nearness and farness are inverted. The phrase kî ʾên ʿôzēr, 'for there is no helper,' identifies the absence of human aid: YHWH is the only recourse, which makes his apparent absence catastrophic.</p>",
"12": "<p><strong>sĕbābûnî pārîm rabbîm ʾabbîrê bāšān kiṯṭĕrûnî</strong> (<em>sĕḇāḇûnî p̄ārîm rabbîm ʾabbîrê ḇāšān kiṯṭĕrûnî</em>): 'Many bulls encompass me; strong bulls of Bashan surround me.' The imagery of bulls — pārîm rabbîm ('many bulls') and ʾabbîrê bāšān ('strong bulls of Bashan') — draws on the famous breeding-stock of Bashan's well-fed pastures (cf. Amos 4:1, where Samaria's oppressive wealthy are called 'cows of Bashan'). The encircling movement — sĕbābûnî ... kiṭṭĕrûnî — suggests being surrounded, cut off, with no exit. The enemies are powerful, well-fed, and coordinated.</p>",
"13": "<p><strong>pāṣû ʿālay pîhem ʾaryēh ṭārēp wĕšōʾēg</strong> (<em>pāṣû ʿālay pîhem ʾaryēh ṭārēp̄ wĕšōʾēḡ</em>): 'they open wide their mouths at me, like a lion ravening and roaring.' The verb pāṣâ ('to open wide') combined with the lion imagery — ʾaryēh ṭārēp ('a lion tearing prey') wĕšōʾēg ('and roaring') — creates the soundscape of predation. The open mouth of the lion is simultaneously an attack (devouring) and a threat display (roaring). The enemies' open mouths echo the mockers of v.7 — hostility expressed through the mouth, whether by derision or by consuming violence.</p>",
"14": "<p><strong>kammayim nišpaktî wĕhitpardĕdû kol-ʿaṣmôtāy</strong> (<em>kammayim nišpaktî wĕhiṯp̄ardĕdû ḵol-ʿaṣmôṯāy</em>): 'I am poured out like water, and all my bones are out of joint.' The two images — poured water and disjointed bones — describe the utter dissolution of physical integrity. The pual nišpaktî ('I am poured out') is passive: the psalmist is not emptying himself but being drained. The verse continues: hāyâ libbî kaddônāg nāmēs bĕtôk mēʿāy, 'my heart has become like wax, melted in the midst of my inward parts.' Wax melting in heat loses its form — the heart's structural capacity for emotion and decision collapses. Early Christian reflection saw in these physical descriptions a prophetic anticipation of crucifixion's physiological reality (hypovolemic shock, joint dislocation).</p>",
"15": "<p><strong>yābēš kāḥerpĕśî kōḥî ûlĕšônî mĕdubbāq malqôḥāy</strong> (<em>yāḇēš ḵāḥerpĕśî ḵōḥî ûlĕšônî mĕḏubbāq malqôḥāy</em>): 'my strength is dried up like a potsherd; and my tongue cleaves to my jaws.' The simile kāḥerpĕśî ('like a potsherd') — a broken fragment of fired clay, completely dehydrated — captures the state of desperate thirst and physical exhaustion. The phrase ûlĕšônî mĕdubbāq malqôḥāy, 'my tongue sticks to my jaws,' is vivid dehydration — the tongue literally adhering to the mouth from lack of moisture. The closing statement wĕlāʿāpar māwet tišpĕtēnî, 'and you lay me in the dust of death,' makes YHWH the agent of this extremity — a radical theology of divine sovereignty over suffering.</p>",
"16": "<p><strong>kî sĕbābûnî kĕlābîm ʿădat mĕrēʿîm hiqqîpûnî</strong> (<em>kî sĕḇāḇûnî ḵĕlāḇîm ʿăḏaṯ mĕrēʿîm hiqqîp̄ûnî</em>): 'for dogs encompass me; a company of evildoers encircles me.' The enemies shift from bulls (v.12) to dogs — the unclean scavengers of the ancient world who consumed corpses. The phrase kārû yādāy wĕraglāy, traditionally rendered 'they have pierced my hands and my feet,' is textually disputed: the MT has kāʾărî ('like a lion'), while some Hebrew manuscripts, the LXX, and Syriac read kārû ('they dug/pierced'). The piercing reading became the primary NT exegetical reading (John 19:37; Luke 24:39; Rev 1:7) for the crucifixion. The Masoretic 'like a lion' makes grammatical sense as an extension of the predator imagery.</p>",
"17": "<p><strong>ʾăsappēr kol-ʿaṣmôtāy hēmmâ yabbîṭû yirʾû-bî</strong> (<em>ʾăsappēr ḵol-ʿaṣmôṯāy hēmmâ yabbîṭû yirʾû-ḇî</em>): 'I can count all my bones — they stare and gloat over me.' The ability to count bones (ʾăsappēr kol-ʿaṣmôtāy) describes the emaciated body: skin pulled tight over protruding bones, every rib visible. The enemies observe this display with yabbîṭû ('they stare') and yirʾû ('they look') — their gaze is that of spectators at an execution, unmoved and satisfied. The spectacle of the dying righteous man as public entertainment is the social context of the passion: 'And sitting down they watched him there' (Matt 27:36).</p>",
"18": "<p><strong>yĕḥallĕqû bĕgādāy lāhem wĕʿal-lĕbûšî yappîlû gôrāl</strong> (<em>yĕḥallĕqû ḇĕḡāḏāy lāhem wĕʿal-lĕḇûšî yappîlû ḡôrāl</em>): 'they divide my garments among them, and for my clothing they cast lots.' The verb ḥālaq (piel, 'to divide, apportion') and the lot-casting (yappîlû gôrāl) for the outer garment are among the most literally-fulfilled prophetic details in the Psalter. John 19:23-24 cites this verse explicitly: 'that the Scripture might be fulfilled, they said, Let us not tear it, but cast lots for it.' John's citation names two garments — the divided outer garments and the un-divided tunic — corresponding to the psalm's two-part description. The precision of the fulfillment citation is unusual even by NT standards.</p>",
"19": "<p><strong>wĕʾattâ YHWH ʾal-tirḥāq ʾeyālûtî lĕʿezrātî ḥûšâ</strong> (<em>wĕʾattâ YHWH ʾal-tirḥāq ʾeyālûṯî lĕʿezrāṯî ḥûšâ</em>): 'But you, O LORD, be not far off; O my strength, come quickly to my aid!' The waw-adversative wĕʾattâ ('but you') — the same structure as v.3 and v.9 — marks a repeated pivot from suffering to address to God. The word ʾeyālûtî ('my strength/might' — from ʾayil, 'ram, strong one') is an unusual divine title, used only here in the Psalter. The imperative ḥûšâ ('hurry!') — from ḥûš ('to move quickly') — adds urgency: not merely 'come' but 'come now.'</p>",
"20": "<p><strong>haṣṣîlâ mēḥereb napšî miyyad-keleb yĕḥîdātî</strong> (<em>haṣṣîlâ mēḥereḇ napšî miyyaḏ-ḵeleḇ yĕḥîḏāṯî</em>): 'Deliver my soul from the sword, my precious life from the power of the dog.' The hiphil haṣṣîlâ ('deliver, snatch away') is an urgent rescue verb. The three paired enemies — sword (ḥereb), dog (keleb), lion (v.21) — represent different modes of violent death. The word yĕḥîdātî ('my only one, my precious/unique life') from yāḥîd ('only, solitary') intensifies the stakes: the psalmist has only one life; its loss cannot be recovered. The LXX reads 'my unique soul' — the soul's uniqueness making its loss irreversible.</p>",
"21": "<p><strong>hôšîʿēnî mippî ʾaryēh ûmiqarnê rēmîm ʿănîtānî</strong> (<em>hôšîʿēnî mippî ʾaryēh ûmiqarnê rēmîm ʿănîtānî</em>): 'Save me from the mouth of the lion; from the horns of the wild oxen you have answered me!' The verse is theologically pivotal: the lament section ends and the praise section begins, but the transition is grammatically abrupt. The qal perfect ʿănîtānî ('you have answered me') is unexpected — suddenly the rescue is narrated as accomplished. Whether this represents a sudden assurance experienced in prayer, or a shift to prophetic confidence, the effect is that death's worst threat (v.15-18) yields to divine answer. The psalm turns on this verb.</p>",
"22": "<p><strong>ʾăsappĕrâ šimkā lĕʾaḥay bĕtôk qāhāl ʾăhallĕlekā</strong> (<em>ʾăsappĕrâ šimkā lĕʾaḥay bĕṯôḵ qāhāl ʾăhallĕleḵā</em>): 'I will tell of your name to my brothers; in the midst of the congregation I will praise you.' The cohortative ʾăsappĕrâ ('I will recount') signals the vow of praise that typically concludes the lament, but here it launches an extended praise section (vv.22-31). Hebrews 2:12 cites this verse as the voice of Jesus: 'I will tell of your name to my brothers, in the midst of the congregation I will sing your praise' — understanding the risen Christ as the one who declares the Father's name to the church. The congregation (qāhāl) is the community of the redeemed.</p>",
"23": "<p><strong>yirʾê YHWH hallĕlûhû kol-zeraʿ yaʿăqōb kabbĕdûhû</strong> (<em>yirʾê YHWH hallĕlûhû ḵol-zeraʿ yaʿăqōḇ kaббĕḏûhû</em>): 'You who fear the LORD, praise him! All you offspring of Jacob, glorify him!' The imperatives — hallĕlûhû ('praise him!'), kabbĕdûhû ('glorify him!'), wĕgûrû mimmennû ('stand in awe of him!') — summon three concentric groups: those who fear YHWH, Jacob's offspring, and Israel. The universal address begins here and expands in vv.27-31. The ground: kî lōʾ-bāzâ wĕlōʾ šiqqaṣ ʿănût ʿānî wĕlōʾ-histîr pānāyw mimmennû, 'for he has not despised or scorned the suffering of the afflicted one; he has not hidden his face from him' (v.24). The praise pivots on the unexpected answer of v.21.</p>",
"24": "<p><strong>kî lōʾ-bāzâ wĕlōʾ šiqqaṣ ʿănût ʿānî</strong> (<em>kî lōʾ-ḇāzâ wĕlōʾ šiqqaṣ ʿănaṯ ʿānî</em>): 'for he has not despised or abhorred the affliction of the afflicted.' The double negation — lōʾ-bāzâ ('has not despised') and lōʾ šiqqaṣ ('has not treated as detestable/abhorred') — are the strongest possible negatives applied to the failure mode the lament feared. The noun ʿănût ʿānî ('the affliction of the afflicted') encompasses the entire suffering of vv.6-21. The theological revolution: what appeared as divine abandonment (v.1) was actually sustained divine attention — ûbĕšawwĿʿô ʾēlāyw šāmaʿ, 'and when he cried to him, he heard.' The hearing was always happening; the abandonment was perceived, not real.</p>",
"25": "<p><strong>mēʾittĕkā tĕhillātî bĕqāhāl rāb</strong> (<em>mēʾittĕḵā tĕhillātî bĕqāhāl rāḇ</em>): 'From you comes my praise in the great assembly.' The phrase mēʾittĕkā ('from you') is theologically significant: even the psalmist's praise is a divine gift, originating in YHWH rather than in the psalmist's autonomous virtue. The plural nĕdārāy ʾăšallēm, 'I will pay my vows' — the vows made in distress (v.22) are now fulfilled in the public worship of the qāhāl rāb ('great congregation'). The assembly of worshippers becomes the theater in which the drama of lament-answered-by-rescue is publicly proclaimed.</p>",
"26": "<p><strong>yōʾkĕlû ʿănāwîm wĕyiśbāʿû</strong> (<em>yōʾḵĕlû ʿănāwîm wĕyiśbāʿû</em>): 'The afflicted shall eat and be satisfied.' The shared meal — yōʾkĕlû ... wĕyiśbāʿû ('they eat and are satisfied') — is the communal dimension of the rescue: the ʿănāwîm ('afflicted, poor, humble') who share the psalmist's condition share also in the celebration. The phrase yĕhallĕlû YHWH dōrĕšāyw yĕḥî lĕbabkem lāʿad, 'those who seek him shall praise the LORD; may your hearts live forever!' introduces yĕḥî lĕbabkem lāʿad ('may your hearts live forever') — a blessing of perpetual life tied to the community of YHWH-seekers. The meal's eschatological overtones anticipate the messianic banquet (Rev 19:9).</p>",
"27": "<p><strong>yizkĕrû wĕyāšûbû ʾel-YHWH kol-ʾapsê-ʾāreṣ</strong> (<em>yizkĕrû wĕyāšûḇû ʾel-YHWH ḵol-ʾapsê-ʾāreṣ</em>): 'All the ends of the earth shall remember and turn to the LORD.' The scope expands from the congregation (v.25-26) to the universe: kol-ʾapsê-ʾāreṣ ('all the ends of the earth') and kol-mišpĕḥôt haggôyim ('all the families of the nations'). The verbs — yizkĕrû ('they shall remember'), yāšûbû ('they shall turn/return'), wĕyištaḥăwû ('they shall bow down') — describe the conversion of the nations as remembering + turning + worship. This sequence mirrors the missionary vision of Ps 67:2-3 and the NT universal proclamation (Acts 1:8; Rev 7:9).</p>",
"28": "<p><strong>kî laYHWH hammelûkâ ûmōšēl baggôyim</strong> (<em>kî laYHWH hammelûkâ ûmōšēl baggôyim</em>): 'for kingship belongs to the LORD, and he rules over the nations.' The divine kingship declaration laYHWH hammelûkâ is absolute: the definite article on hammelûkâ ('the kingship') asserts that there is only one legitimate sovereign, and it belongs to YHWH. The participle mōšēl ('the one who rules') expresses ongoing governance. This verse is the theological center of vv.27-31: the universal conversion of nations is grounded in the universality of YHWH's sovereignty — all must turn to him because he already rules them.</p>",
"29": "<p><strong>ʾāklû wĕhištaḥăwû kol-dišnê-ʾereṣ</strong> (<em>ʾāḵlû wĕhišṯaḥăwû ḵol-dišnê-ʾereṣ</em>): 'All the prosperous of the earth eat and bow down.' The phrase dišnê-ʾereṣ ('the fat ones of the earth') — the wealthy and powerful — also bow. Worship is not limited to the poor (v.26) but extends to the prosperous. The counterpart: kol-yôrĕdê ʿāpār wĕnapšô lōʾ ḥiyyâ, 'before him shall bow all who go down to the dust, even the one who cannot keep his soul alive.' Even the dying, those reduced to dust (returning to Gen 3:19's ʿāpār), worship. Death itself is not an exception to divine sovereignty.</p>",
"30": "<p><strong>zeraʿ yaʿăbĕdennû yĕsuppār laʾdōnāy laddôr</strong> (<em>zeraʿ yaʿăḇoḏennû yĕsuppār laʾḏōnāy laḏḏôr</em>): 'A seed shall serve him; it shall be told of the Lord to the coming generation.' The noun zeraʿ ('seed, offspring') looks forward: the rescue of the psalmist generates a continuing community of servants. The phrase yĕsuppār laʾdōnāy laddôr ('it shall be told of the Lord to the coming generation') describes inter-generational witness — each generation hears and tells. The passive yĕsuppār ('it shall be told') implies that the story propagates on its own power: the report of YHWH's rescue is self-perpetuating good news.</p>",
"31": "<p><strong>yābōʾû wĕyaggîdû ṣidqātô lĕʿam nôlād kî ʿāśâ</strong> (<em>yāḇōʾû wĕyaḡḡîdû ṣiḏqāṯô lĕʿam nôlāḏ kî ʿāśâ</em>): 'They shall come and proclaim his righteousness to a people yet to be born, that he has done it.' The final phrase kî ʿāśâ, 'that he has done it' — two Hebrew words, among the most theologically dense in the Psalter — is the summary of the psalm's entire movement: God acted. This bare declaration is the kerygmatic core: from dereliction (v.1) to proclamation (v.31), the entire psalm is the testimony of one who cried out, was answered, and now tells. The psalm ends not with the psalmist's experience but with the report going forward to ʿam nôlād ('a people yet to be born') — the endless echo of rescue through history.</p>"
},
"23": {
"1": "<p><strong>YHWH rōʿî lōʾ ʾeḥsār</strong> (<em>YHWH rōʿî lōʾ ʾeḥsār</em>): 'The LORD is my shepherd; I shall not want.' The opening declaration YHWH rōʿî ('the LORD is my shepherd') is the psalm's entire theology in three words: divine identity (YHWH), relational role (rōʿeh/'shepherd'), and personal claim (rōʿî/'my shepherd'). The shepherd metaphor (rāʿâ) in the ANE was applied to kings — the king as shepherd of his people — but here inverted: the divine King functions as the personal shepherd of the individual. The result: lōʾ ʾeḥsār ('I shall not want/lack') — a permanent negation of deprivation. Jesus applies this psalm to himself in John 10:11, 14: 'I am the good shepherd.'</p>",
"2": "<p><strong>binʾôt dešeʾ yarbîṣēnî</strong> (<em>ḇinʾôṯ dešeʾ yarḇîṣēnî</em>): 'He makes me lie down in green pastures.' The hiphil yarbîṣēnî ('he makes me lie down') is causative: the lying down is not self-initiated but given by the shepherd. The phrase binʾôt dešeʾ ('in green/tender grass pastures') — the nāʾweh ('beautiful pasture') lush with vegetation — captures provision. The second image, ʿal-mê mĕnûḥôt yĕnahălēnî, 'he leads me beside still waters,' uses the hiphil nāhal ('to lead to a watering place') — a term specifically for leading animals to water. The mê mĕnûḥôt ('waters of stillness/rest') are not turbulent; they are the calm pools from which sheep can drink without fear.</p>",
"3": "<p><strong>napšî yĕšôbēb</strong> (<em>napšî yĕšôḇēḇ</em>): 'He restores my soul.' The polel yĕšôbēb (from šûb, 'to turn/return') means 'he causes to return, restores.' The soul (nepeš) exhausted or diverted is brought back to its proper orientation by the shepherd. The phrase yanhēnî bĕmaʿgĕlê ṣedeq, 'he leads me in paths of righteousness,' uses maʿgāl ('track, well-worn path') — the grooves worn by repeated passage through correct routes. The decisive qualifier: lĕmaʿan šĕmô ('for his name's sake') — the shepherd's guidance serves not primarily the sheep's comfort but the divine reputation. YHWH leads rightly because his name is at stake.</p>",
"4": "<p><strong>gam kî ʾēlēk bĕgê ṣalmāwet lōʾ ʾîrāʾ rāʿ</strong> (<em>ḡam kî ʾēlēk bĕḡê ṣalmāwet lōʾ ʾîrāʾ rāʿ</em>): 'Even though I walk through the valley of the shadow of death, I will fear no evil.' The phrase gê ṣalmāwet ('valley of deep darkness/shadow of death') — from ṣalmāwet ('deep darkness, death-shadow') — describes the most terrifying terrain. The ḡam kî ('even though, even if') is concessive: the peril is real, not imaginary. The consequent: lōʾ ʾîrāʾ rāʿ ('I will not fear evil') — complete fearlessness grounded in divine presence: kî ʾattâ ʿimmādî, 'for you are with me.' The instruments šibṭĕkā ûmišʿantekā, 'your rod and your staff,' are the shepherd's tools — the šēbeṭ for protection against predators, the mišʿenet for guiding sheep.</p>",
"5": "<p><strong>taʿărōk lĕpānay šûlḥān neged ṣōrĕrāy</strong> (<em>taʿărōḵ lĕp̄ānay šûlḥān negeḏ ṣōrĕrāy</em>): 'You prepare a table before me in the presence of my enemies.' The shift in imagery from shepherd/sheep to host/guest is striking — v.5 enters the realm of banquet hospitality. The table (šulḥān) set before (lĕpānay) the psalmist neged ṣōrĕrāy ('in the sight of my adversaries') is a public act: the enemies witness the psalmist being honored. The verb diššantā bĕšemen rōʾšî, 'you anoint my head with oil,' describes the honored guest receiving perfumed oil at a feast. The concluding kôsî rĕwāyâ, 'my cup overflows,' uses the niphal of rāwâ ('to be saturated, overflow') — abundance beyond capacity.</p>",
"6": "<p><strong>ʾak ṭôb wāḥesed yirdĕpûnî kol-yĕmê ḥayyāy</strong> (<em>ʾaḵ ṭôḇ wāḥeseḏ yirḏĕp̄ûnî ḵol-yĕmê ḥayyāy</em>): 'Surely goodness and steadfast love shall follow me all the days of my life.' The particle ʾak ('surely, only') is emphatic certainty. The verb rādap ('pursue, follow hotly') — normally used of enemies pursuing — is here applied to ṭôb wāḥesed ('goodness and steadfast love'): divine blessings as relentless pursuers who will not allow the psalmist to escape them. The final phrase wĕšabttî bĕbêt YHWH lĕʾōrek yāmîm, 'and I shall dwell in the house of the LORD forever,' uses šûb ('return, dwell') — the psalmist's permanent orientation is toward the divine dwelling. The psalm ends where theology must end: in the house of the shepherd-king.</p>"
},
"24": {
"1": "<p><strong>laYHWH hāʾāreṣ ûmĕlōʾāh tēbēl wĕyōšĕbê bāh</strong> (<em>laYHWH hāʾāreṣ ûmĕlōʾāh tēḇēl wĕyōšĕḇê ḇāh</em>): 'The earth is the LORD's and the fullness thereof, the world and those who dwell in it.' The psalm opens with a creation-sovereignty declaration that Paul cites in 1 Cor 10:26 regarding the lawfulness of eating food offered to idols — if the earth belongs to YHWH, no corner of it is excluded from his lordship. The double statement — hāʾāreṣ ûmĕlōʾāh ('the earth and its fullness') and tēbēl wĕyōšĕbê bāh ('the world and those who dwell in it') — encompasses both the land and its inhabitants. The definite laYHWH ('to/belonging to the LORD') is exclusive ownership.</p>",
"2": "<p><strong>kî hûʾ ʿal-yammîm yĕsādāh</strong> (<em>kî hûʾ ʿal-yammîm yĕsāḏāh</em>): 'for he has founded it upon the seas.' The verb yāsad (piel, 'to found, establish') describes YHWH as creator and sustainer of the cosmic order. The phrase ʿal-yammîm yĕsādāh wĕʿal-nĕhārôt yĕkônĕnehā, 'he has established it upon the rivers,' draws on the ancient cosmology of the earth founded above primordial waters (Gen 1:9-10; Ps 136:6). The founding of the earth on the seas is the ground of YHWH's ownership: the creator owns the creation. This cosmological foundation makes the entrance-liturgy of vv.3-10 coherent — only the creator's anointed can stand on this holy mountain.</p>",
"3": "<p><strong>mî yāʿăleh bĕhar YHWH ûmî yāqûm bimqôm qodšô</strong> (<em>mî yāʿăleh ḇĕhar YHWH ûmî yāqûm bimqôm qodšô</em>): 'Who shall ascend the hill of the LORD? And who shall stand in his holy place?' The double rhetorical question mirrors Ps 15:1. The verb ʿālâ ('to go up, ascend') is the pilgrimage term (cf. ʿaliyyâ to Jerusalem); qûm bimqôm qodšô ('stand in his holy place') is the liturgical term for entering the sanctuary precinct and remaining. The answer given in v.4 is moral, not ritual — not ceremonial purity but ethical integrity qualifies one to ascend.</p>",
"4": "<p><strong>nĕqî kappayim ûbar lēbāb</strong> (<em>nĕqî ḵappayim ûḇar lēḇāḇ</em>): 'He who has clean hands and a pure heart.' The binary of hands and heart — outward act and inward disposition — defines integrity comprehensively. nĕqî kappayim ('clean of hands') denotes innocent of bloodshed and unethical dealings; bar lēbāb ('pure/clear of heart') denotes undivided loyalty. Matt 5:8 ('blessed are the pure in heart') echoes the lēb bārûr. The next clause: ʾăšer lōʾ nāśāʾ laššāwĕʾ napšô wĕlōʾ nišbaʿ lĕmirmâ, 'who does not lift up his soul to what is false, and does not swear deceitfully' — adds truthfulness in oath-taking (cf. Ps 15:4) as a second criterion.</p>",
"5": "<p><strong>yiśśāʾ bĕrākâ mēʾēt YHWH ûṣĕdāqâ mēʾĕlōhê yišʿô</strong> (<em>yiśśāʾ ḇĕrāḵâ mēʾēṯ YHWH ûṣĕḏāqâ mēʾĕlōhê yišʿô</em>): 'He will receive blessing from the LORD and righteousness from the God of his salvation.' The one who qualifies (v.4) receives bĕrākâ ('blessing') and ṣĕdāqâ ('righteousness') — both from YHWH. The ṣĕdāqâ here is not mere ethical standing but the verdict of righteousness from the divine judge: to be declared righteous by the God who saves. The phrase ʾĕlōhê yišʿô ('the God of his salvation') personalizes it — this is 'my God who saves.'</p>",
"6": "<p><strong>zeh dôr dōrĕšāyw mĕbaqqĕšê pānêkā yaʿăqōb</strong> (<em>zeh dôr dōrĕšāyw mĕbaqqĕšê p̄āneḵā yaʿăqōḇ</em>): 'Such is the generation of those who seek him, who seek your face, O Jacob.' The dôr ('generation') of seekers is the community defined not by birth but by orientation — those who seek (dāraš) YHWH and seek his face (bāqaš pānêkā). The address 'O Jacob' (Selah) is unusual — it may be a gloss or liturgical call. The generation of seekers constitutes the people of God in each era: the covenant community is defined by the pattern of life described in v.4, not ethnic origin.</p>",
"7": "<p><strong>śĕʾû šĕʿārîm rāšêkem wĕhinnāśĕʾû pitḥê ʿôlām wĕyābôʾ melek hakkābôd</strong> (<em>śĕʾû šĕʿārîm rāšêkem wĕhinnāśĕʾû piṯḥê ʿôlām wĕyāḇôʾ meleḵ haḵḵāḇôḏ</em>): 'Lift up your heads, O gates! And be lifted up, O ancient doors, that the King of glory may come in.' The imperatives — śĕʾû ('lift up!') and hinnāśĕʾû ('be lifted up!') — personify the gates as figures bowing before a greater king. The phrase melek hakkābôd ('the King of glory') — YHWH as the kābôd-bearing sovereign — is the psalm's climactic title. The setting was likely the procession of the ark into Jerusalem (2 Sam 6) or an annual liturgical re-enactment. The NT applies the entry imagery to the ascension of Christ through the heavenly gates (Heb 1:6; Ps 47:5).</p>",
"8": "<p><strong>mî zeh melek hakkābôd YHWH ʿizzûz wĕgibbôr</strong> (<em>mî zeh meleḵ haḵḵāḇôḏ YHWH ʿizzûz wĕḡibbôr</em>): 'Who is this King of glory? The LORD, strong and mighty.' The dialogue format — question (v.8a) / answer (v.8b) — may reflect a liturgical antiphony between two groups: those outside the gate asking, those inside answering. The divine title YHWH ʿizzûz wĕgibbôr YHWH gibbôr milḥāmâ, 'the LORD, strong and mighty, the LORD, mighty in battle,' invokes the divine warrior tradition (Exod 15:3; Isa 42:13). YHWH's glory is specifically the glory of a warrior who wins battles — a counter-claim against any military power that oppresses Israel.</p>",
"9": "<p><strong>śĕʾû šĕʿārîm rāšêkem ûśĕʾû pitḥê ʿôlām</strong> (<em>śĕʾû šĕʿārîm rāšêkem ûśĕʾû piṯḥê ʿôlām</em>): 'Lift up your heads, O gates! Lift them up, O ancient doors.' The repetition of the summons (cf. v.7) with slight variation — the second half reads ûśĕʾû rather than wĕhinnāśĕʾû — creates the intensification of liturgical repetition. The repetition is not redundancy but escalation: the call goes out a second time, more urgent. The doors (pitḥê ʿôlām, 'eternal doors') are designated by their antiquity — they have witnessed ages of divine activity; now they open for the greatest entrance.</p>",
"10": "<p><strong>mî hûʾ zeh melek hakkābôd YHWH ṣĕbāʾôt hûʾ melek hakkābôd</strong> (<em>mî hûʾ zeh meleḵ haḵḵāḇôḏ YHWH ṣĕḇāʾôṯ hûʾ meleḵ haḵḵāḇôḏ</em>): 'Who is this King of glory? The LORD of hosts, he is the King of glory!' The final identification YHWH ṣĕbāʾôt ('LORD of hosts/armies') is the most comprehensive divine title in the Psalter — YHWH as the commander of the heavenly armies (the stars, angels, and cosmic forces). The declaration hûʾ melek hakkābôd ('he is the King of glory') is the psalm's answer to the question it has posed throughout: the one who owns the earth (v.1), who founded it (v.2), whose holy mountain is approached only by the ethically qualified (vv.3-6), who enters in military triumph (vv.7-9) — this one is the LORD of hosts. Selah closes the psalm with a meditative pause on the name.</p>"
},
"25": {
"1": "<p><strong>ʾēlêkā YHWH napšî ʾeśśāʾ</strong> (<em>ʾēlêḵā YHWH napšî ʾeśśāʾ</em>): 'To you, O LORD, I lift up my soul.' Psalm 25 is an acrostic psalm — each verse begins with the successive letter of the Hebrew alphabet. The opening gesture — lifting the soul (nepeš) to YHWH — is an act of total self-offering: the self (nepeš = life-breath, will, appetite) directed entirely toward God. The preposition ʾēlêkā ('toward you') and the perfect tense of surrender set the psalm's posture: not merely asking but orienting the entire self toward the divine.</p>",
"2": "<p><strong>ʾĕlōhay bĕkā bāṭaḥtî ʾal-ʾēbôšâ</strong> (<em>ʾĕlōhay bĕḵā ḇāṭaḥtî ʾal-ʾēḇôšâ</em>): 'O my God, in you I trust; let me not be put to shame.' The pairing bāṭaḥtî ('I trust') with ʾal-ʾēbôšâ ('let me not be put to shame') shows that shame is the ultimate risk of trust: if YHWH does not respond, the psalmist's public reliance is exposed as futile. The phrase ʾal-yaʿalĕṣû ʾōyĕbay lî, 'let not my enemies exult over me,' is the social dimension — the enemy's victory would be the psalmist's humiliation. Trust in God is a public stake that requires God to act in order to vindicate both the psalmist and himself.</p>",
"3": "<p><strong>gam kol-qōwêkā lōʾ yēbōšû</strong> (<em>ḡam ḵol-qōwêḵā lōʾ yēḇōšû</em>): 'Indeed, none who wait for you shall be put to shame.' The qāwâ ('to wait, hope with taut expectation') group — all those who wait on YHWH — are collectively protected from shame. The contrast: yēbōšû habbôgĕdîm rêqām, 'those who are wantonly treacherous shall be put to shame.' The word rêqām ('empty-handed, in vain') characterizes the treacherous: they pursue betrayal but achieve nothing lasting. Shame is redirected from the trusting to the treacherous.</p>",
"4": "<p><strong>dĕrāḵêkā YHWH hôdîʿēnî ʾōrĕḥôtêkā lammĕdēnî</strong> (<em>dĕrāḵêḵā YHWH hôḏîʿēnî ʾōrĕḥôṯêḵā lammĕḏēnî</em>): 'Make me to know your ways, O LORD; teach me your paths.' The two pedagogical imperatives — hôdîʿēnî ('make me know') and lammĕdēnî ('teach me') — are requests for covenantal guidance. The pair dĕrāḵêkā ('your ways') and ʾōrĕḥôtêkā ('your paths') — both plural — suggest multiple dimensions of the divine will, not a single rigid rule. The request is not for information but for formation: to be shaped into a person who walks in YHWH's ways habitually.</p>",
"5": "<p><strong>haddirēkēnî bĕʾamittĕkā wĕlammĕdēnî</strong> (<em>haḏḏirēḵēnî ḇĕʾămiṯṯĕḵā wĕlammĕḏēnî</em>): 'Lead me in your truth and teach me.' The hiphil haddirēkēnî ('lead, guide') from dārak ('to tread a path') asks for active divine direction, not passive instruction. The prepositional phrase bĕʾamittĕkā ('in your truth/faithfulness') uses ʾĕmet ('truth, reliability') as the medium of guidance: YHWH's truth is not merely propositional but the way on which one walks. The confession: kî ʾattâ ʾĕlōhê yišʿî, 'for you are the God of my salvation' — grounds the request in covenant identity. The phrase ʾôtĕkā qiwwîtî kol-hayyôm ('you I wait for all the day') sustains the ʿal-qōwêkā of v.3.</p>",
"6": "<p><strong>zĕkōr-raḥămêkā YHWH waḥăsādeykā kî mēʿôlām hēmmâ</strong> (<em>zĕḵor-raḥămêḵā YHWH waḥăsāḏeḵā kî mēʿôlām hēmmâ</em>): 'Remember your mercy, O LORD, and your steadfast love, for they have been from of old.' The imperative zĕkōr ('remember!') is the covenantal appeal: YHWH's raḥămîm ('mercies, compassion' — from reḥem/'womb,' the deep visceral tenderness of a mother) and ḥăsādîm ('acts of steadfast love') have a history — mēʿôlām hēmmâ, 'they have been from of old.' The prayer is not asking for a novel attribute but for the continuation of YHWH's established pattern of compassion. Memory becomes the engine of covenant faithfulness.</p>",
"7": "<p><strong>ḥaṭṭōʾt nĕʿûray ûpĕšāʿay ʾal-tizkor</strong> (<em>ḥaṭṭōʾṯ nĕʿûray ûp̄ĕšāʿay ʾal-tizkor</em>): 'Remember not the sins of my youth or my transgressions.' The prayer inverts v.6: the psalmist asks God to remember (ḥăsādîm) and to forget (ḥaṭṭōʾt). The pairing ḥaṭṭōʾt ('sins, failures to hit the mark') and pĕšāʿîm ('transgressions, deliberate rebellions') covers the full range of moral failure. The phrase nĕʿûray ('of my youth') acknowledges that the young have always been vulnerable to folly — the past is real but need not define the future. The appeal: kĕḥasdĕkā zĕkār-lî ʾattâ lĕmaʿan ṭûbĕkā YHWH, 'according to your steadfast love remember me, for your goodness' sake, O LORD' — the ground of forgiveness is divine character (ḥesed, ṭôb), not human merit.</p>",
"8": "<p><strong>ṭôb wĕyāšār YHWH ʿal-kēn yôreh ḥaṭṭāʾîm baddārek</strong> (<em>ṭôḇ wĕyāšār YHWH ʿal-kēn yôreh ḥaṭṭāʾîm baḏḏāreḵ</em>): 'Good and upright is the LORD; therefore he instructs sinners in the way.' The declaration ṭôb wĕyāšār ('good and upright') describes YHWH's character. The logical connector ʿal-kēn ('therefore, on account of this') makes the instruction of sinners a consequence of divine character, not human worthiness: YHWH teaches sinners precisely because he is good. The noun ḥaṭṭāʾîm ('sinners') — the same people whose sins are addressed in v.7 — are not excluded from divine guidance; they are its target. This is grace-as-pedagogy.</p>",
"9": "<p><strong>yanhēl ʿănāwîm bammišpāṭ wîlammēd ʿănāwîm darkô</strong> (<em>yanĕhēl ʿănāwîm bammišpāṭ wîlammēḏ ʿănāwîm darkô</em>): 'He leads the humble in what is right, and teaches the humble his way.' The key word ʿănāwîm ('humble, meek, afflicted') — those who are bent down, whether by external oppression or by internal posture — are the specific recipients of divine guidance. The noun mišpāṭ ('justice, right') as the medium of leading means YHWH guides through his established order of justice, not arbitrary preference. Jesus's beatitude 'blessed are the meek' (Matt 5:5) echoes the Psalter's consistent elevation of the ʿānāw as the one who inherits the earth (Ps 37:11).</p>",
"10": "<p><strong>kol-ʾōrĕḥôt YHWH ḥesed wĕʾĕmet lĕnōṣĕrê bĕrîtô wĕʿēdōtāyw</strong> (<em>ḵol-ʾōrĕḥôṯ YHWH ḥeseḏ wĕʾĕmeṯ lĕnōṣĕrê ḇĕrîṯô wĕʿēḏōṯāyw</em>): 'All the paths of the LORD are steadfast love and faithfulness, for those who keep his covenant and his testimonies.' The comprehensive claim kol-ʾōrĕḥôt ('all the paths') eliminates exceptions: every way YHWH leads is characterized by ḥesed wĕʾĕmet ('steadfast love and faithfulness'). The qualifier lĕnōṣĕrê bĕrîtô wĕʿēdōtāyw, 'for those who keep his covenant and his testimonies,' identifies the covenant community as the context in which this promise operates — not a universal guarantee but a covenant-shaped assurance.</p>",
"11": "<p><strong>lĕmaʿan šimkā YHWH wĕsālaḥtā laʿăwōnî kî rāb hûʾ</strong> (<em>lĕmaʿan šimkā YHWH wĕsālaḥtā laʿăwōnî kî rāḇ hûʾ</em>): 'For your name's sake, O LORD, pardon my guilt, for it is great.' The appeal lĕmaʿan šimkā ('for your name's sake') grounds the request in divine honor rather than human claim: the psalmist does not argue his worthiness but YHWH's reputation. The strikingly honest phrase kî rāb hûʾ, 'for it is great' — the guilt's greatness is the very reason for the request. The logic inverts: normally great guilt would disqualify; here it intensifies the appeal. Only a God of extraordinary grace can handle great guilt — and YHWH is that God.</p>",
"12": "<p><strong>mî-zeh hāʾîš yĕrēʾ YHWH yôrennû bĕdārek yibḥār</strong> (<em>mî-zeh hāʾîš yĕrēʾ YHWH yôrennû bĕḏāreḵ yiḇḥār</em>): 'Who is the man who fears the LORD? Him will he instruct in the way that he should choose.' The rhetorical question mî-zeh hāʾîš, 'who is the man?' recalls Ps 24:3-4 — the entrance liturgy question about qualification. Here the qualifier is yĕrēʾ YHWH ('fearing the LORD') — the foundational orientation from which all wisdom flows (Prov 1:7). The result: yôrennû bĕdārek yibḥār, 'he will instruct him in the way he should choose.' YHWH teaches the God-fearer how to make life's choices — wisdom as the fruit of reverence.</p>",
"13": "<p><strong>napšô bĕṭôb tālîn wĕzarʿô yîraš ʾāreṣ</strong> (<em>napšô bĕṭôḇ tālîn wĕzarʿô yîraš ʾāreṣ</em>): 'His soul shall abide in well-being, and his offspring shall inherit the land.' The promise napšô bĕṭôb tālîn, 'his soul shall lodge in prosperity' — using lûn ('to lodge overnight, rest') suggests the well-being is settled and abiding, not temporary. The generational extension wĕzarʿô yîraš ʾāreṣ, 'and his offspring shall inherit the land,' draws on the covenantal promise of the land (Gen 12:7; Ps 37:11). The blessing of the God-fearing extends beyond the individual to the next generation. Matt 5:5's 'they shall inherit the earth' universalizes the land promise.</p>",
"14": "<p><strong>sôd YHWH lîrēʾāyw ûbĕrîtô lĕhôdîʿām</strong> (<em>sôḏ YHWH lîrēʾāyw ûḇĕrîṯô lĕhôḏîʿām</em>): 'The friendship of the LORD is for those who fear him, and he makes known to them his covenant.' The noun sôd ('council, intimate circle, secret counsel') — used of the divine council (Jer 23:18; Job 15:8) — here describes the intimate fellowship YHWH offers to the God-fearing: not merely information about the covenant but inclusion in YHWH's own inner circle. The phrase ûbĕrîtô lĕhôdîʿām, 'and he makes his covenant known to them,' is the content of the sôd: covenant-knowledge as the shared secret of divine friendship.</p>",
"15": "<p><strong>ʿênay tāmîd ʾel-YHWH kî hûʾ yôṣî mĕrešet raglāy</strong> (<em>ʿênay tāmîd ʾel-YHWH kî hûʾ yôṣî mĕrešeṯ raglāy</em>): 'My eyes are ever toward the LORD, for he will pluck my feet out of the net.' The phrase ʿênay tāmîd ʾel-YHWH, 'my eyes always toward the LORD,' describes the posture of constant orientation — not periodic turning but sustained gaze. The ground kî hûʾ yôṣî mĕrešet raglāy, 'for he will pluck my feet out of the net,' uses yāṣāʾ (hiphil, 'to bring out, pluck out') for rescue from the reŝet ('net, snare') — the traps set by enemies (cf. Ps 10:9; 22:20). Trust is gaze; gaze enables rescue.</p>",
"16": "<p><strong>pĕnēh-ʾēlay wĕḥonnēnî kî-yāḥîd wĕʿānî ʾānî</strong> (<em>p̄ĕnēh-ʾēlay wĕḥonnēnî kî-yāḥîd wĕʿānî ʾānî</em>): 'Turn to me and be gracious to me, for I am lonely and afflicted.' The double self-description yāḥîd ('alone, solitary') and ʿānî ('afflicted, poor') identifies the psalmist's condition: isolated and beaten down. The imperative pĕnēh ('turn toward me!') — literally the divine face turning — requests the personal attention of YHWH. The word ḥonnēnî ('be gracious to me!') invokes the ḥānan/ḥesed cluster of divine favor. Loneliness before God is the psalm's deepest pain: not merely suffering but suffering in perceived isolation from the divine.</p>",
"17": "<p><strong>ṣārôt lĕbābî hirḥîbû mimmeṣûqôtay hôṣîʾēnî</strong> (<em>ṣārôt lĕḇāḇî hirḥîḇû mimmeṣûqôṯay hôṣîʾēnî</em>): 'The troubles of my heart are enlarged; bring me out of my distresses.' The idiom ṣārôt lĕbābî hirḥîbû ('the troubles of my heart have enlarged') describes how distress expands to fill the interior — anxieties that grow until they dominate the entire inner landscape. The imperative hôṣîʾēnî ('bring me out!') from yāṣāʾ ('to go out') is the rescue term — the same verb used in Exod 13:3 for the Exodus. The psalmist prays for a personal exodus from his meṣûqôt ('straits, tight places').</p>",
"18": "<p><strong>rĕʾēh ʿonyî waʿămālî wĕśāʾ lĕkol-ḥaṭṭōʾtāy</strong> (<em>rĕʾēh ʿonyî waʿămālî wĕśāʾ lĕḵol-ḥaṭṭōʾṯāy</em>): 'Consider my affliction and my trouble, and forgive all my sins.' The imperative rĕʾēh ('see, consider') requests divine attention to the external (ʿonî, 'affliction') and internal (ʿāmāl, 'toil, trouble') dimensions of suffering. The addition wĕśāʾ lĕkol-ḥaṭṭōʾtāy, 'and lift off all my sins,' connects suffering to sin — not necessarily causally but covenantally: the psalmist acknowledges that complete deliverance requires both external rescue and internal forgiveness. The verb nāśāʾ ('to lift up, carry away') as the verb for forgiveness captures the removal of the burden (cf. Lev 16:22).</p>",
"19": "<p><strong>rĕʾēh ʾôyĕbay kî rabbû wĕśinʾat ḥāmās śĕnēʾûnî</strong> (<em>rĕʾēh ʾôyĕbay kî rabbû wĕśinʾaṯ ḥāmās śĕnēʾûnî</em>): 'Consider how many are my enemies, and with what violent hatred they hate me.' The resumptive rĕʾēh ('consider/see') repeats v.18's opening: look at both the sin (internal) and the enemies (external). The phrase śinʾat ḥāmās śĕnēʾûnî ('with hatred of violence they hate me') is a cognate accusative intensifier — the hating is characterized by ḥāmās ('violence, destructive force'). The enemies' hatred is not merely emotional but operational: they intend violence.</p>",
"20": "<p><strong>šomrâ napšî wĕhaṣṣîlēnî ʾal-ʾēbôš kî ḥāsîtî bāk</strong> (<em>šomrâ napšî wĕhaṣṣîlēnî ʾal-ʾēḇôš kî ḥāsîṯî ḇāḵ</em>): 'Keep my soul and deliver me; let me not be put to shame, for I take refuge in you.' The paired imperatives šomrâ ('guard!') and haṣṣîlēnî ('deliver!') bracket the prayer: constant protection and active rescue. The shame-avoidance ʾal-ʾēbôš recalls v.2 — the psalm is framed by the fear of shame. The ground ḥāsîtî bāk ('I have taken refuge in you') is the basis: since the psalmist has publicly committed to YHWH as refuge, YHWH's honor is bound up with the outcome.</p>",
"21": "<p><strong>tōm wĕyōšer yiṣṣĕrûnî kî qiwwîtîkā</strong> (<em>ṯōm wĕyōšer yiṣṣĕrûnî kî qiwwîtîkā</em>): 'May integrity and uprightness preserve me, for I wait for you.' The nouns tōm ('completeness, integrity') and yōšer ('uprightness, straightness') function as guardians — the psalmist's own moral character as protective companions. The reason: kî qiwwîtîkā, 'for I wait for you' — covenant faithfulness expressed as patient, taut expectation. The verse restates the psalm's posture: integrity-shaped waiting as the practical form of covenant trust.</p>",
"22": "<p><strong>pĕdēh ʾĕlōhîm ʾet-yiśrāʾēl mikkōl ṣārôtāyw</strong> (<em>p̄ĕḏēh ʾĕlōhîm ʾeṯ-yiśrāʾēl miḵḵōl ṣārôṯāyw</em>): 'Redeem Israel, O God, out of all his troubles.' The closing verse breaks the acrostic (it is a pê verse appended after the ṣādê verse) and shifts from individual to national concern. The verb pādâ ('redeem, ransom') — one of the key exodus/salvation verbs — applied to Israel as a whole suggests that the individual psalmist's experience of needing rescue mirrors Israel's corporate situation. The move from personal prayer to corporate intercession is characteristic of psalmic theology: the individual's faith is never separable from the community's hope.</p>"
},
"26": {
"1": "<p><strong>šopĕṭēnî YHWH kî ʾănî bĕtummî hālāktî</strong> (<em>šop̄ĕṭēnî YHWH kî ʾănî bĕṯummî hālāḵtî</em>): 'Vindicate me, O LORD, for I have walked in my integrity.' Psalm 26 is a protestation of innocence — a genre related to the oath of clearance in which the accused declares their innocence before God (cf. Job 31). The verb šāpaṭ ('judge, vindicate') is a legal request: not punishment but examination and exoneration. The phrase bĕtummî hālāktî, 'I have walked in my integrity,' uses tōm ('completeness, wholeness') — the same word as Ps 25:21. The accompanying confession ûbaYHWH bāṭaḥtî lōʾ ʾemʿāḍ, 'and in the LORD I trust without wavering,' frames the integrity as covenant-grounded, not self-generated.</p>",
"2": "<p><strong>bĕḥānēnî YHWH wĕnassēnî ṣārĕpâ kilĕyôtay wĕlibbî</strong> (<em>bĕḥānēnî YHWH wĕnassēnî ṣārĕp̄â ḵilĕyôṯay wĕlibbî</em>): 'Prove me, O LORD, and try me; test my heart and my mind.' The three verbs — bāḥan ('examine'), nāsâ ('test, try'), and ṣārap ('smelt, refine') — all describe metallurgical or judicial investigation. The objects kilĕyôtay ('my kidneys/reins' — the seat of deep feeling) and libbî ('my heart' — the center of will and thought) encompass the whole inner person: both emotion and cognition. The psalmist invites the most thorough possible divine inspection, confident that the examination will vindicate rather than condemn.</p>",
"3": "<p><strong>kî ḥasdĕkā lĕneged ʿênāy wĕhithallaktî bĕʾamittekā</strong> (<em>kî ḥasdĕḵā lĕnegeḏ ʿênāy wĕhiṯhallakṯî bĕʾămiṯṯeḵā</em>): 'for your steadfast love is before my eyes, and I walk in your faithfulness.' The phrase lĕneged ʿênāy ('before my eyes') — used elsewhere for what one constantly sees and is shaped by — means the psalmist's vision is constituted by YHWH's ḥesed: the divine love is his constant reference point. The hitpael wĕhithallaktî ('I walked about / I conduct myself') from hālak suggests habitual, lifestyle-level behavior — not isolated acts but the ongoing pattern of walking in ʾĕmet (faithfulness/truth).</p>",
"4": "<p><strong>lōʾ-yāšabtî ʿim-mĕtê-šāwĕʾ</strong> (<em>lōʾ-yāšabtî ʿim-mĕtê-šāwĕʾ</em>): 'I do not sit with men of falsehood.' The negative lōʾ-yāšabtî ('I have not sat') followed by the parallel lōʾ ʾābôʾ ('I will not go in') with ʿim nĕʿālamîm ('with those who hide themselves/dissemblers') describe separation from the morally compromised. The company one keeps shapes the character one has: the psalmist's integrity is maintained partly by the associations he avoids. mĕtê-šāwĕʾ ('men of falsehood/vanity') and nĕʿālamîm ('those who cloak themselves, hypocrites') are the two groups he refuses to inhabit.</p>",
"5": "<p><strong>śānēʾtî qĕhal mĕrēʿîm wĕʿim rĕšāʿîm lōʾ ʾēšēb</strong> (<em>śānēʾṯî qĕhal mĕrēʿîm wĕʿim rĕšāʿîm lōʾ ʾēšēb</em>): 'I hate the assembly of evildoers, and I will not sit with the wicked.' The verb śānēʾ ('to hate') is strong — not merely avoid but actively reject. The noun qāhāl ('assembly, congregation') used for mĕrēʿîm ('evildoers') is a deliberate anti-type to the qāhāl of YHWH's worshippers (v.12). The two assemblies — the evildoers' and the righteous — are mutually exclusive: one cannot inhabit both. The psalmist's claim to innocence rests partly on sustained non-participation in the alternative community.</p>",
"6": "<p><strong>ʾerḥaṣ bĕnikkāyôn kappāy wăʾăsōbbĕbâ ʾet-mizbaḥăkā YHWH</strong> (<em>ʾerḥaṣ bĕnikkāyôn kappāy wăʾăsōḇḇĕḇâ ʾeṯ-mizḇaḥăḵā YHWH</em>): 'I wash my hands in innocence and go around your altar, O LORD.' The verb rāḥaṣ ('to wash') applied to the hands is a ritual purity gesture, but here deployed metaphorically for moral innocence (bĕnikkāyôn, 'in cleanness/innocence'). The Pilate parallel (Matt 27:24) uses the same gesture in reverse: he washes his hands to disclaim responsibility while the crowd accepts blood-guilt. The psalmist's hand-washing is a claim; Pilate's is a denial. The verb sābab ('go around, encircle') describes the processional circumambulation of the altar — active participation in worship, not passive attendance.</p>",
"7": "<p><strong>lĕhašmîaʿ bĕqôl tôdâ ûlĕsappēr kol-niplĕʾôtêkā</strong> (<em>lĕhašmîaʿ bĕqôl tôḏâ ûlĕsappēr ḵol-nipl̂ĕʾôṯeḵā</em>): 'proclaiming thanksgiving aloud, and telling all your wondrous deeds.' The two infinitives — lĕhašmîaʿ ('to cause to be heard') and lĕsappēr ('to recount, tell') — describe the content of the worshipper's participation: thanksgiving (tôdâ) and narration of niplĕʾôt ('wonders, marvelous deeds'). The tôdâ was both a thanksgiving offering and the liturgical speech accompanying it. The psalmist's worship is verbal proclamation — witness embedded in liturgy.</p>",
"8": "<p><strong>YHWH ʾāhabtî mĕʿôn bêtekā ûmĕqôm miškan kĕbôdekā</strong> (<em>YHWH ʾāhaḇtî mĕʿôn bêṯeḵā ûmĕqôm miškan kĕḇôḏeḵā</em>): 'O LORD, I love the habitation of your house and the place where your glory dwells.' The declaration ʾāhabtî ('I love') — qal perfect, completed and ongoing — applied to mĕʿôn bêtekā ('the dwelling of your house') expresses the psalmist's deepest affection as being for the sanctuary. The phrase mĕqôm miškan kĕbôdekā, 'the place where your glory dwells,' uses the theological kābôd — the radiant divine presence that filled the tabernacle (Exod 40:34-35) and temple (1 Kgs 8:10-11). Love of the sanctuary is love of the presence it houses.</p>",
"9": "<p><strong>ʾal-tʾĕsōp ʿim-ḥaṭṭāʾîm napšî wĕʿim-ʾanšê dāmîm ḥayyāy</strong> (<em>ʾal-tʾăsōp ʿim-ḥaṭṭāʾîm napšî wĕʿim-ʾanšê ḏāmîm ḥayyāy</em>): 'Do not sweep away my soul with sinners, nor my life with bloodthirsty men.' The verb ʾāsap ('to gather, sweep away') in negative imperative form — ʾal-tʾĕsōp ('do not gather away') — pictures divine judgment as a gathering-and-sweeping of the wicked. The psalmist's prayer: do not include me in that sweep. The phrase ʾanšê dāmîm ('men of blood') designates murderers and the violent; their distinguishing characteristic is bloodshed. The psalmist's protestation of innocence throughout the psalm is precisely the ground for this request.</p>",
"10": "<p><strong>ʾăšer bîdêhem zimmâ wîmînām māleʾâ šōḥad</strong> (<em>ʾăšer bîḏêhem zimmâ wîmînām māleʾâ šōḥad</em>): 'in whose hands are evil devices, and whose right hands are full of bribes.' The noun zimmâ ('evil plan, wickedness') describes premeditated wrongdoing — schemes carried in the hands. The right hand (yāmîn) māleʾâ šōḥad, 'full of bribes,' corrupts the justice system: the šōḥad perverts the judge's verdict, converting justice into commerce. This is precisely what Ps 15:5 and Ps 24:4 identified as disqualifying from divine presence — and why the psalmist protests his own innocence: his hands are ʾerḥaṣ bĕnikkāyôn (v.6), not full of bribes.</p>",
"11": "<p><strong>waʾănî bĕtummî ʾēlēk pĕdēnî wĕḥonnēnî</strong> (<em>waʾănî bĕṯummî ʾēlēḵ p̄ĕḏēnî wĕḥonnēnî</em>): 'But as for me, I walk in my integrity; redeem me and be gracious to me.' The waw-adversative waʾănî ('but as for me') creates the contrast with the bloodthirsty of vv.9-10. The confession bĕtummî ʾēlēk ('I walk in my integrity') returns to the psalm's opening claim (v.1) — inclusio formed by the same language. The paired imperatives pĕdēnî ('redeem me!') and ḥonnēnî ('be gracious to me!') place the psalmist's need entirely in YHWH's hands: integrity does not earn rescue; it gives YHWH a basis to act in covenant faithfulness.</p>",
"12": "<p><strong>raglî ʿāmĕdâ bĕmîšôr bĕmaqhēlîm ʾăbārēk YHWH</strong> (<em>raḡlî ʿāmĕḏâ bĕmîšôr bĕmaqhēlîm ʾăḇārēḵ YHWH</em>): 'My foot stands on level ground; in the great assembly I will bless the LORD.' The phrase raglî ʿāmĕdâ bĕmîšôr, 'my foot stands on level ground,' uses mîšôr ('level plain, evenness') — the same root as yāšār ('upright'). The foot that walked in integrity (v.1) now stands on level ground — a spatial metaphor for moral stability. The vow bĕmaqhēlîm ʾăbārēk YHWH, 'in the great assembly I will bless the LORD,' returns the psalm to the sanctuary of v.8: the individual's protestation of innocence culminates in corporate worship. Integrity leads to praise.</p>"
},
"27": {
"1": "<p><strong>YHWH ʾôrî wĕyišʿî mimmî ʾîrā YHWH māʿôz ḥayyay mimmî ʾepḥad</strong> (<em>YHWH ʾôrî wĕyišʿî mimmî ʾîrā YHWH māʿôz ḥayyay mimmî ʾep̄ḥaḏ</em>): 'The LORD is my light and my salvation; whom shall I fear? The LORD is the stronghold of my life; of whom shall I be afraid?' The psalm opens with a triple divine declaration: YHWH as ʾôr ('light'), yešûʿâ ('salvation'), and māʿôz ('stronghold/refuge'). The light-metaphor (ʾôr) denotes guidance, revelation, and life itself — the opposite of darkness and death (cf. Isa 9:2; John 8:12). The rhetorical questions mimmî ʾîrā / mimmî ʾepḥad ('whom shall I fear? / of whom shall I be afraid?') eliminate every ground for fear: if YHWH is all three, no human power can threaten what matters most.</p>",
"2": "<p><strong>biqrōb ʿālay mĕrēʿîm leʾĕkōl ʾet-bĕśārî</strong> (<em>biqrōḇ ʿālay mĕrēʿîm leʾĕḵōl ʾeṯ-bĕśārî</em>): 'When evildoers assail me to eat up my flesh.' The verb ʾākal ('eat') applied to flesh — leʾĕkōl ʾet-bĕśārî — is a violent metaphor for total consumption/destruction (cf. Ps 14:4). The enemies are mĕrēʿîm ('evildoers') who approach (qārob, 'draw near') with intent to destroy. The reversal: hēmmâ kāšĕlû wĕnāpālû, 'they stumbled and fell.' The perfects are perfects of confidence — the psalmist narrates the defeat as already accomplished. The approach of enemies results in their own collapse before the one they attacked.</p>",
"3": "<p><strong>ʾim taḥăneh ʿālay maḥăneh lōʾ-yîrā libbî</strong> (<em>ʾim taḥăneh ʿālay maḥăneh lōʾ-yîrā libbî</em>): 'Though an army encamp against me, my heart shall not fear.' The hypothetical ʾim ('though, even if') introduces extreme test cases: an encamped army (maḥăneh — the same term for Israel's camp in the wilderness) and war (milḥāmâ) arrayed against the psalmist. The response of the heart (lēb): lōʾ-yîrā ('shall not fear') and lōʾ ʾeṭaḥ ('I will remain confident/trust'). The noun biṣṣōʾt ('in this' — the crisis) is the circumstance that occasions the confidence declaration: not despite the danger but precisely in it.</p>",
"4": "<p><strong>ʾaḥat šāʾaltî mēʾēt YHWH ʾôtāh ʾăbaqqēš</strong> (<em>ʾaḥat šāʾaltî mēʾēt YHWH ʾôṯāh ʾăḇaqqēš</em>): 'One thing have I asked of the LORD, that will I seek after.' The emphatic ʾaḥat ('one thing') narrows the entire scope of prayer to a single petition — the concentration of all desire into one longing. The petition: šibtî bĕbêt-YHWH kol-yĕmê ḥayyay lĕḥăzôt bĕnoʿam YHWH ûlĕbaqqēr bĕhêkālô, 'to dwell in the house of the LORD all the days of my life, to gaze upon the beauty of the LORD and to inquire in his temple.' The three infinitives — šibtî ('dwelling'), lĕḥăzôt ('gazing'), ûlĕbaqqēr ('inquiring') — constitute the fullness of sanctuary life: permanence, contemplation, and seeking. The noʿam YHWH ('beauty/pleasantness of the LORD') is the ultimate object of vision (cf. Ps 16:11; Rev 22:4).</p>",
"5": "<p><strong>kî yiṣpĕnēnî bĕsukkōh bĕyôm rāʿâ</strong> (<em>kî yiṣp̄ĕnēnî bĕsukkōh bĕyôm rāʿâ</em>): 'for he will hide me in his shelter in the day of trouble.' The verb ṣāpan (piel, 'to hide, treasure up') pictures YHWH concealing the psalmist in sukkō ('his shelter/booth') — the divine dwelling as protective cover. The second image: yastirēnî bĕsēter ʾohŏlô, 'he will conceal me under the cover of his tent' (the tabernacle as hiding place). The third: yĕrômĕmēnî ʿal-ṣûr ('he will set me high upon a rock') — elevation beyond the reach of enemies. The day of trouble (yôm rāʿâ) does not nullify the confidence of v.1-3 but confirms its necessity.</p>",
"6": "<p><strong>wĕʿattâ yārûm rōʾšî ʿal ʾōyĕbay sĕbîbôtay</strong> (<em>wĕʿattâ yārûm rōʾšî ʿal ʾōyĕbay sĕḇîḇôṯay</em>): 'And now my head shall be lifted up above my enemies all around me.' The raising of the head (yārûm rōʾšî) is the reversal of the bowing/humiliation the enemies sought. The vow that follows: wĕʾezbeḥâ bĕʾohŏlô zibbĕḥê tĕrûʿâ ʾāšîrâ waʾăzammĕrâ laYHWH, 'I will offer in his tent sacrifices with shouts of joy; I will sing and make melody to the LORD.' The sacrifices of tĕrûʿâ ('shouting, alarm/joy') transform military victory into liturgical offering: the battle's outcome becomes the occasion for worship.</p>",
"7": "<p><strong>šmaʿ YHWH qôlî ʾeqrāʾ wĕḥonnēnî waʿănēnî</strong> (<em>šmaʿ YHWH qôlî ʾeqrāʾ wĕḥonnēnî waʿănēnî</em>): 'Hear, O LORD, when I cry aloud; be gracious to me and answer me.' The psalm's second half (vv.7-14) shifts from confidence declaration to active prayer — suggesting the psalm was composed in two movements or that the confident first section empowers the petition of the second. The trio šmaʿ ('hear!'), ḥonnēnî ('be gracious to me!'), and waʿănēnî ('answer me!') are the classic lament imperatives. Even confident trust expresses itself in explicit petition.</p>",
"8": "<p><strong>lĕkā ʾāmar libbî baqqĕšû pānāy ʾet-pānêkā YHWH ʾăbaqqēš</strong> (<em>lĕḵā ʾāmar libbî baqqĕšû p̄ānāy ʾeṯ-p̄āneḵā YHWH ʾăḇaqqēš</em>): 'You have said, 'Seek my face.' My heart says to you, 'Your face, LORD, do I seek.'' The divine imperative baqqĕšû pānāy ('seek my face!') — whether heard in Scripture, liturgy, or internal conviction — is met with immediate response: ʾeṯ-pānêkā YHWH ʾăbaqqēš ('your face, O LORD, I seek'). The two-part structure of divine invitation and human response is the grammar of prayer: God's call precedes and elicits the seeking. The pānîm ('face') — divine self-disclosure — is both the command's content and the prayer's object.</p>",
"9": "<p><strong>ʾal-tastēr pānêkā mimmennî ʾal-taṭ bĕʾap ʿabdekā</strong> (<em>ʾal-tastēr p̄āneḵā mimmennî ʾal-taṭ bĕʾap ʿaḇḏeḵā</em>): 'Hide not your face from me; turn not your servant away in anger.' The negative imperatives — ʾal-tastēr ('do not hide!') and ʾal-taṭ bĕʾap ('do not turn away in anger!') — are prayers against divine wrath and hiddenness. The psalmist has been seeking the face (v.8) and now fears the face might be hidden — the very hiding that Ps 22:1 lamented. The continued address ʿabdekā ('your servant') maintains the relational framework: servant-speech is the human position before the sovereign YHWH. The phrase ʾĕzrātî hāyîtā, 'you have been my help,' appeals to prior experience to ground present petition.</p>",
"10": "<p><strong>kî-ʾābî wĕʾimmî ʿăzābûnî waYHWH yaʾasĕpēnî</strong> (<em>kî-ʾāḇî wĕʾimmî ʿăzāḇûnî waYHWH yaʾasĕp̄ēnî</em>): 'For my father and my mother have forsaken me, but the LORD will take me in.' The extreme hypothetical — parental abandonment — represents the deepest human betrayal: even the most natural and binding of bonds may fail. The response waYHWH yaʾasĕpēnî, 'but the LORD will take me in/gather me' — from ʾāsap ('gather, receive') — images YHWH as the one who gathers the abandoned child. The statement grounds the appeal of v.9: if even parents might fail, YHWH's faithfulness must not. This is the Psalter's most poignant expression of YHWH as the ultimate parent (cf. Isa 49:15).</p>",
"11": "<p><strong>hôrēnî YHWH darkekā ûnaḥēnî bĕʾōraḥ mîšôr lĕmaʿan šôrĕrāy</strong> (<em>hôrēnî YHWH darkekā ûnaḥēnî bĕʾōraḥ mîšôr lĕmaʿan šôrĕrāy</em>): 'Teach me your way, O LORD, and lead me on a level path because of my enemies.' The request hôrēnî ('teach me!') from yārâ ('to throw, point, teach') — the root of tôrâ — asks for foundational instruction in divine direction. The phrase bĕʾōraḥ mîšôr ('on a level/even path') echoes Ps 25:21 (tōm) and Ps 26:12 (mîšôr): moral levelness as protection from stumbling. The enemies are the context: lĕmaʿan šôrĕrāy, 'because of my enemies/those who watch me,' who would exploit any deviation.</p>",
"12": "<p><strong>ʾal-tittĕnēnî bĕnepeš ṣārāy</strong> (<em>ʾal-tittĕnēnî bĕnepeš ṣārāy</em>): 'Give me not up to the will of my adversaries.' The phrase bĕnepeš ṣārāy ('into the desire/appetite of my adversaries') — nepeš as 'appetite, desire' (rather than 'soul') — means: do not let them have what they hunger for, which is my destruction. The motive clause kî qāmû bî ʿēdê šāqer wîpēaḥ ḥāmās, 'for false witnesses have risen against me, and they breathe out violence,' specifies the judicial danger: perjury in court. ʿēdê šāqer ('false witnesses') is a specific violation of the Decalogue (Exod 20:16) — the psalmist faces coordinated legal assault backed by lies.</p>",
"13": "<p><strong>lûlēʾ heʾĕmantî lirʾôt bĕṭûb YHWH bĕʾereṣ ḥayyîm</strong> (<em>lûlēʾ heʾĕmantî lirʾôt bĕṭûḇ YHWH bĕʾereṣ ḥayyîm</em>): 'I believe that I shall look upon the goodness of the LORD in the land of the living.' The phrase lûlēʾ ('unless, if not') begins a conditional whose main clause is suppressed — a classical rhetorical aposiopesis: 'If I had not believed... [I would have despaired].' What remains is the content of the faith: lirʾôt bĕṭûb YHWH bĕʾereṣ ḥayyîm, 'to see the goodness of the LORD in the land of the living.' The ṭûb YHWH ('goodness of the LORD') is the object of faith-based vision — not merely hoped for in the afterlife but expected in this life. ʾereṣ ḥayyîm ('land of the living') = the present world of embodied existence, not the realm of the dead.</p>",
"14": "<p><strong>qawwēh ʾel-YHWH ḥăzaq wĕyaʾămēṣ libbĕkā wĕqawwēh ʾel-YHWH</strong> (<em>qawwēh ʾel-YHWH ḥăzaq wĕyaʾămēṣ libbĕḵā wĕqawwēh ʾel-YHWH</em>): 'Wait for the LORD; be strong, and let your heart take courage; wait for the LORD!' The double imperative qawwēh ... qawwēh ('wait ... wait') — from qāwâ ('to wait with taut, rope-like expectation') — frames the verse as an inclusio of hope. Between the two waits: ḥăzaq wĕyaʾămēṣ libbĕkā ('be strong and let your heart take courage') — the verbs used for Joshua's commissioning (Josh 1:6-9) and David's charge to Solomon (1 Chr 22:13). The courageous heart is not self-manufactured but the result of waiting on YHWH — confidence drawn from the one waited for. The psalm ends not with resolution but with the ongoing posture of expectation.</p>"
}
}

def main():
    existing = load_comm('mkt-original', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-original', 'psalms', existing)
    total = sum(len(v) for v in PSALMS.values())
    print(f'Psalms 22-27 mkt-original written — {total} new verse entries attempted.')

if __name__ == '__main__': main()
